INSERT INTO `comments` VALUES (147,114,52,NULL,'Love how you broke down the steps. The setup logic is super practical for next time.',0,'1976-06-03 00:33:32'),(148,112,62,NULL,'Perfect timing. Student-budget ideas always help, definitely saving this for my next run.',0,'1976-06-03 00:33:32'),(149,156,44,NULL,'This is so detailed. You convinced me to start stretching too—writing this down.',0,'1976-06-03 00:33:50'),(150,113,39,NULL,'Your descriptions are vivid. That route sounds ideal for a chill weekend walk.',0,'1976-06-03 00:33:32'),(151,130,44,NULL,'This is motivating. I really need to clean my desk like this—saving for later.',0,'1976-06-03 00:33:41'),(152,136,45,NULL,'Saved. I’ve been looking for a spot like this—definitely trying it soon.',0,'1976-06-03 00:33:41'),(153,158,67,NULL,'The practice log feels real and doable. I think I can try this soon.',0,'1976-06-03 00:33:50'),(154,151,61,NULL,'Saved. Budget-friendly tips are everything right now—this is genuinely helpful.',0,'1976-06-03 00:33:42'),(155,191,53,NULL,'Saved—your color combo looks so calm and wearable. Noting this down.',0,'1976-06-03 00:34:00'),(156,271,65,NULL,'Saved. The budget breakdown is super clear—this will help me plan my next one.',0,'1976-06-03 00:34:20'),(157,171,56,NULL,'The vibe sounds amazing. I feel like I could try this soon—really helpful.',0,'1976-06-03 00:33:51'),(158,218,57,NULL,'Saved! I’m going to steal this playlist idea—genuinely helpful for study days.',0,'1976-06-03 00:34:02'),(159,149,43,NULL,'This feels so real and trackable. I think I can try it soon—saving it.',0,'1976-06-03 00:33:42'),(160,97,48,NULL,'Saved. That color pairing is super comfortable-looking—definitely noting this down.',0,'1976-06-03 00:33:32'),(161,280,51,NULL,'This came at the right time. The atmosphere you described sounds so cozy—saving.',0,'1976-06-03 00:34:21'),(162,201,43,NULL,'I had a similar experience. Your note structure is really clear and easy to follow.',0,'1976-06-03 00:34:01'),(163,106,